dark.customCSS:
/* Animated gradient — Aurora Borealis */
body {
  background-image: linear-gradient(135deg, #0a0a2e, #1a3a5c, #0d7377, #1a3a5c, #0a0a2e) !important;
  background-attachment: fixed !important;
  background-size: 400% 400% !important;
  animation: auroraShift 16s ease infinite !important;
}
@keyframes auroraShift {
  0%   { background-position: 0% 50%; }
  50%  { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

/* Make layout containers transparent */
#app, #app > div, #app > div > div, main, .app,
.bg-gray-900, .bg-gray-950,
.dark\:bg-gray-900, .dark\:bg-gray-950 {
  background-color: transparent !important;
  background-image: none !important;
}

/* Blend chat/folder background images with gradient */
#chat-container .bg-linear-to-t {
  background-image: linear-gradient(
    to top, rgba(10, 10, 46, 0.7), rgba(13, 115, 119, 0.35)
  ) !important;
}

/* Sidebar & input readability */
#sidebar {
  background-color: rgba(10, 10, 46, 0.7) !important;
  backdrop-filter: blur(12px) !important;
}
textarea {
  background-color: rgba(10, 10, 46, 0.5) !important;
  backdrop-filter: blur(8px) !important;
}

dark.canvasScript:
/**
 * Title: Blue Lightning Twinkle
 * Description: Converted directly from tsParticles 'Twinkle' network config.
 */

const CONFIG = {
    particleCount: 80,
    color: 'rgba(255, 0, 0, 1)',
    linkColor: 'rgba(255, 255, 255, 0.4)',
    linkDistance: 150,
    minSize: 0.1,
    maxSize: 5,
    speed: 2,
    opacityMin: 0.1,
    opacityMax: 0.5
};

let canvas, ctx, w, h;
let particles = [];
let mouse = { x: -5000, y: -5000 };

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x; mouse.y = e.data.y;
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    particles = [];
    for (let i = 0; i < CONFIG.particleCount; i++) {
        particles.push({
            x: Math.random() * w, y: Math.random() * h,
            vx: (Math.random() - 0.5) * CONFIG.speed,
            vy: (Math.random() - 0.5) * CONFIG.speed,
            size: Math.random() * (CONFIG.maxSize - CONFIG.minSize) + CONFIG.minSize,
            opacity: Math.random() * (CONFIG.opacityMax - CONFIG.opacityMin) + CONFIG.opacityMin,
            opacityDir: Math.random() > 0.5 ? 1 : -1
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);

    for (let i = 0; i < particles.length; i++) {
        let p = particles[i];
        p.x += p.vx; p.y += p.vy;

        p.opacity += p.opacityDir * 0.01;
        if (p.opacity >= CONFIG.opacityMax) { p.opacity = CONFIG.opacityMax; p.opacityDir = -1; }
        if (p.opacity <= CONFIG.opacityMin) { p.opacity = CONFIG.opacityMin; p.opacityDir = 1; }

        if (p.x < 0) p.x = w; if (p.x > w) p.x = 0;
        if (p.y < 0) p.y = h; if (p.y > h) p.y = 0;

        for (let j = i + 1; j < particles.length; j++) {
            let p2 = particles[j];
            let dx = p.x - p2.x; let dy = p.y - p2.y;
            let dist = Math.hypot(dx, dy);

            if (dist < CONFIG.linkDistance) {
                ctx.beginPath();
                ctx.strokeStyle = CONFIG.linkColor;
                ctx.lineWidth = 1;
                ctx.moveTo(p.x, p.y);
                ctx.lineTo(p2.x, p2.y);
                ctx.stroke();
            }
        }

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(255, 0, 0, ${p.opacity})`;
        ctx.fill();
    }

    requestAnimationFrame(render);
}

